let p = msg.payload || {};
let raw = (p.content || "").trim();

// In gemischtem Text NUR die URL extrahieren
// Matcht amzn.to UND amzn.eu in JEDEM Kontext
const urlMatch = raw.match(/https?:\/\/amzn\.(to|eu)\/[^\s]+/i);

msg.telegram = p;
msg.originalInput = raw;

if (urlMatch) {
    // Extrahierte Short-URL
    msg.needsResolve = true;
    msg.url = urlMatch[0];
    return msg;
}

// Kein Shortlink gefunden
msg.needsResolve = false;
return msg;

const telegram = msg.telegram || {};
const chatId = telegram.chatId;

let finalUrl = null;

// Wenn Redirects gefolgt wurden → finale URL hier
if (msg.responseUrl) {
    finalUrl = msg.responseUrl;
}

// Fallback: Falls doch nur Location gesetzt wurde (sollte bei followRedirects=true selten sein)
if (!finalUrl && msg.headers && msg.headers.location) {
    finalUrl = msg.headers.location;
}

if (!finalUrl) {
    msg.payload = {
        chatId,
        type: "message",
        content: "Fehler beim Auflösen des Shortlinks."
    };
    return msg;
}

msg.payload = {
    chatId,
    content: finalUrl
};

return msg;

// Nur Nachrichten dieser Chat-ID
const allowedChatId = 297934858;

let p = msg.payload;
if (typeof p === "string") {
    try { p = JSON.parse(p); } catch (e) { return null; }
}
if (!p || p.chatId !== allowedChatId) return null;

// --- INPUT robust machen (Telegram/Markdown-Wrapper entfernen) ---
let input = (p.content || "").trim();
input = input
    .replace(/^<(.+)>$/, "$1")   // <https://...>
    .replace(/^\((.+)\)$/, "$1") // (https://...)
    .replace(/^\[(.+)\]$/, "$1");// [https://...]

// Default-Tracking-ID aus globalem Kontext (Inject-Node)
let defaultTracking = global.get("defaultTrackingId") || "meintechblog-251007-21";
let trackingId = context.get("trackingId") || defaultTracking;
let lastAsin = context.get("lastAsin") || null;

function buildUrl(asin, tracking) {
    return `https://www.amazon.de/dp/${asin}?tag=${tracking}`;
}

function isValidDate(day, month, yearStr) {
    let year = yearStr.length === 4 ? parseInt(yearStr, 10) : 2000 + parseInt(yearStr, 10);
    const d = new Date(year, month - 1, day);
    return d.getFullYear() === year && d.getMonth() === (month - 1) && d.getDate() === day;
}

function extractAsin(url) {
    // deckt u.a. ab:
    // /dp/ASIN, /gp/product/ASIN, /product/ASIN, /exec/obidos/ASIN/ASIN
    const regex = /\/(?:dp|gp\/product|product|exec\/obidos\/ASIN)\/(B0[A-Z0-9]{8})\b/i;
    const match = url.match(regex);
    return match ? match[1].toUpperCase() : null;
}

// RESET
if (input.toLowerCase() === "reset") {
    trackingId = defaultTracking;
    context.set("trackingId", trackingId);

    if (!lastAsin) {
        return {
            payload: {
                chatId: allowedChatId,
                type: "message",
                content: `OK — Tracking-ID zurückgesetzt: ${trackingId}`
            }
        };
    }

    return {
        payload: {
            chatId: allowedChatId,
            type: "message",
            content: `OK — Tracking-ID zurückgesetzt: ${trackingId}\n\n${buildUrl(lastAsin, trackingId)}`
        }
    };
}

// ---------- HEUTE ----------
if (input.toLowerCase() === "heute") {
    // aktuelles Datum ermitteln
    let d = new Date();
    let yy = String(d.getFullYear()).slice(2);       // z.B. "25"
    let mm = String(d.getMonth() + 1).padStart(2, "0");
    let dd = String(d.getDate()).padStart(2, "0");

    let todayTS = `${yy}${mm}${dd}`;  // z.B. "250221"

    trackingId = `meintechblog-${todayTS}-21`;
    context.set("trackingId", trackingId);

    // Wenn noch keine ASIN gespeichert → nur OK
    if (!lastAsin) {
        return {
            payload: {
                chatId: allowedChatId,
                type: "message",
                content: `OK — Tracking-ID gesetzt: ${trackingId}`
            }
        };
    }

    // Wenn ASIN vorhanden → fertige URL sofort ausgeben
    return {
        payload: {
            chatId: allowedChatId,
            type: "message",
            content: buildUrl(lastAsin, trackingId)
        }
    };
}

// TIMESTAMP YYMMDD
if (/^[0-9]{6}$/.test(input)) {
    const yy = input.slice(0, 2);
    const mm = input.slice(2, 4);
    const dd = input.slice(4, 6);

    if (!isValidDate(parseInt(dd, 10), parseInt(mm, 10), yy)) {
        return {
            payload: {
                chatId: allowedChatId,
                type: "message",
                content: `Ungültiges Datum im Format YYMMDD: ${input}`
            }
        };
    }

    trackingId = `meintechblog-${input}-21`;
    context.set("trackingId", trackingId);

    if (!lastAsin) {
        return {
            payload: {
                chatId: allowedChatId,
                type: "message",
                content: `OK — neue Tracking-ID gesetzt: ${trackingId}`
            }
        };
    }

    return {
        payload: {
            chatId: allowedChatId,
            type: "message",
            content: buildUrl(lastAsin, trackingId)
        }
    };
}

// ---------- DATUM: D.M.YY / DD.MM.YY / D.M.YYYY / DD.MM.YYYY ----------
const dateMatch = input.match(/^(\d{1,2})\.(\d{1,2})\.(\d{2}|\d{4})$/);

if (dateMatch) {
    const day = parseInt(dateMatch[1], 10);
    const month = parseInt(dateMatch[2], 10);
    const yearPart = dateMatch[3];

    // gültiges Datum prüfen
    if (!isValidDate(day, month, yearPart)) {
        return {
            payload: {
                chatId: allowedChatId,
                type: "message",
                content: `Ungültiges Datum: ${input}`
            }
        };
    }

    // Jahr 4-stellig → auf 2-stellig reduzieren
    const year2 = yearPart.length === 4 ? yearPart.slice(2) : yearPart;

    // Timestamp bauen YYMMDD
    const ts =
        `${year2}` +
        `${String(month).padStart(2, "0")}` +
        `${String(day).padStart(2, "0")}`;

    trackingId = `meintechblog-${ts}-21`;
    context.set("trackingId", trackingId);

    if (!lastAsin) {
        return {
            payload: {
                chatId: allowedChatId,
                type: "message",
                content: `OK — neue Tracking-ID gesetzt: ${trackingId}`
            }
        };
    }

    return {
        payload: {
            chatId: allowedChatId,
            type: "message",
            content: buildUrl(lastAsin, trackingId)
        }
    };
}

// Amazon-URL (amazon.* oder amzn.* – falls direkt Produkt-URL / Shortlink)
if (/^(https?:\/\/)?(www\.)?(amazon\.[a-z.]+|amzn\.(to|eu))\//i.test(input)) {
    const asin = extractAsin(input);

    if (!asin) {
        return {
            payload: {
                chatId: allowedChatId,
                type: "message",
                content: "Konnte keine ASIN aus der URL extrahieren."
            }
        };
    }

    context.set("lastAsin", asin);

    return {
        payload: {
            chatId: allowedChatId,
            type: "message",
            content: buildUrl(asin, trackingId)
        }
    };
}

// Direkte ASIN
if (/^B0[A-Z0-9]{8}$/i.test(input)) {
    const asin = input.toUpperCase();
    context.set("lastAsin", asin);

    return {
        payload: {
            chatId: allowedChatId,
            type: "message",
            content: buildUrl(asin, trackingId)
        }
    };
}

// Fallback
return {
    payload: {
        chatId: allowedChatId,
        type: "message",
        content:
            `Unbekanntes Format.

Gültige Eingaben:
• ASIN (B0XXXXXXXX)
• Amazon-URL
• Shortlink (amzn.to / amzn.eu)
• Datum YYMMDD
• Datum DD.MM.YY / DD.MM.YYYY
• heute
• reset`
    }
};
